#include <bits/stdc++.h>
using namespace std;

const int N=65;

int n,m,dis[N];
bool f[N][N][N],g[N][N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        f[u][v][0]=1;
    }
    for(int i=1;i<N;i++)
        for(int j=1;j<=n;j++)
            for(int k=1;k<=n;k++)
                for(int l=1;l<=n;l++)
                    f[j][k][i]=max(f[j][k][i],f[j][l][i-1] && f[l][k][i-1]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            for(int k=0;k<N;k++)
                if(f[i][j][k]){
                    g[i][j]=1;
                    break;
                }
    memset(dis,0x3f,sizeof(dis));
    queue<int> q;
    q.push(1),dis[1]=0;
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=1;i<=n;i++)
            if(g[x][i] && dis[i]>dis[x]+1){
                dis[i]=dis[x]+1;
                q.push(i);
            }
    }
    printf("%d\n",dis[n]);
    return 0;
}
